# Base shapes module - interfaces and abstract classes

interface IDrawable:
    def draw(self) -> str
    def shape_type(self) -> int

@abstract
class IMeasurable:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

